add_action('wp_footer', function() {
?>
<script>
document.addEventListener("DOMContentLoaded", function () {

  const slider = document.querySelector("#carousel");

  if (!slider) return;

  let isDown = false;      // indica se il mouse è premuto
  let startX;              // posizione iniziale del mouse
  let scrollLeft;          // scroll iniziale del div

  // quando premi il mouse sul carosello
  slider.addEventListener("mousedown", (e) => {
    isDown = true;
    slider.classList.add("dragging");
    startX = e.pageX - slider.offsetLeft;
    scrollLeft = slider.scrollLeft;
  });

  // quando esci dal carosello
  slider.addEventListener("mouseleave", () => {
    isDown = false;
    slider.classList.remove("dragging");
  });

  // quando rilasci il mouse
  slider.addEventListener("mouseup", () => {
    isDown = false;
    slider.classList.remove("dragging");
  });

  // movimento del mouse mentre tieni premuto
  slider.addEventListener("mousemove", (e) => {
    if (!isDown) return;
    e.preventDefault();

    const x = e.pageX - slider.offsetLeft;
    const walk = (x - startX) * 1.5; // velocità trascinamento
    slider.scrollLeft = scrollLeft - walk;
  });

});
</script>
<?php
});
